def find_max(lst):
    current_max = lst[0]
    for num in lst:
        if num > current_max:
            current_max = num
    return current_max

print(find_max([3, 1, 4, 1, 5, 9, 2, 6]))

def all_pairs(lst):
    pairs = []
    for i in lst:
        for j in lst:
            pairs.append((i, j))
    return pairs

# A loop inside a loop. If n doubles, work quadruples.
print(all_pairs([1, 2, 3]))

def binary_search(lst, target):
    left, right = 0, len(lst) - 1
    while left <= right:
        mid = (left + right) // 2
        if lst[mid] == target:
            return mid
        elif lst[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

# Each step cuts remaining work in half.
print(binary_search([1, 3, 5, 7, 9, 11], 7))

